import type { AdContext, AdDisplayPolicy } from "./AdDisplayPolicy";
import { CooldownCondition } from "./conditions/CooldownCondition";
import { PlatformAdapter } from "../adapter/PlatformAdapter";

const DEFAULT_NATIVE_AD_COOLDOWN_MS = 4 * 60 * 60 * 1000;
const ONLINE_AD_RETRY_STORAGE_KEY = "digivice_pending_online_ad_retry";
const OFFLINE_FALLBACK_AD_RETRY_INTERVAL_MS = 1000;

type OfflineInterstitialFallbackResult =
  | "fallback_completed"
  | "ad_shown"
  | false;

function resolveCooldownMs(metadata: Record<string, unknown> | undefined) {
  const cooldownMs = metadata?.cooldownMs;

  if (
    typeof cooldownMs === "number" &&
    Number.isFinite(cooldownMs) &&
    cooldownMs > 0
  ) {
    return cooldownMs;
  }

  return DEFAULT_NATIVE_AD_COOLDOWN_MS;
}

/**
 * 광고 관리자
 * 정책을 관리하고 광고 표시를 결정
 */
export class AdManager {
  private policies: AdDisplayPolicy[] = [];
  private platformAdapter: PlatformAdapter;

  constructor() {
    this.platformAdapter = new PlatformAdapter();
  }

  /**
   * 정책 추가
   */
  addPolicy(policy: AdDisplayPolicy): void {
    this.policies.push(policy);
    // 우선순위 순으로 정렬
    this.policies.sort((a, b) => b.getPriority() - a.getPriority());
    console.log(`[AdManager] Policy added: ${policy.name}`);
  }

  /**
   * 광고 요청
   * @param trigger 트리거 이벤트
   * @param context 광고 컨텍스트
   */
  async requestAd(
    trigger: string,
    context: Partial<AdContext> = {},
  ): Promise<boolean> {
    const fullContext: AdContext = {
      trigger,
      isCharacterUrgent: false,
      ...context,
    };

    console.log("[AdManager] Ad requested:", fullContext);

    // 네이티브 환경이 아니면 로그만
    if (!this.platformAdapter.isRunningInNativeApp()) {
      console.log("[AdManager] Not running in native app - ad request ignored");
      return false;
    }

    // AdController 존재 확인
    if (!window.adController) {
      console.warn("[AdManager] window.adController not available");
      return false;
    }

    // 정책 체크
    const policy = await this.findMatchingPolicy(fullContext);
    if (!policy) {
      console.log("[AdManager] No matching policy found");
      return false;
    }

    console.log(`[AdManager] Policy matched: ${policy.name}`);
    const cooldownMs = resolveCooldownMs(fullContext.metadata);
    const isOnlineRetry = fullContext.metadata?.onlineRetry === true;

    // 네이티브 쿨다운 체크 (안전장치)
    try {
      const canShowStr = await window.adController.canShowAd({ cooldownMs });
      const canShow = canShowStr === "true";

      if (!canShow) {
        console.log("[AdManager] Blocked by native cooldown");
        return false;
      }
    } catch (error) {
      console.error("[AdManager] Error checking native cooldown:", error);
      return false;
    }

    // 광고 표시
    try {
      await window.adController.showInterstitial({ cooldownMs });
      console.log("[AdManager] Ad shown successfully");

      // 쿨다운 업데이트
      CooldownCondition.updateCooldown();
      if (isOnlineRetry) {
        this.clearPendingOnlineAdRetry();
      }

      return true;
    } catch (error) {
      console.error("[AdManager] Error showing ad:", error);
      if (isOnlineRetry) {
        return false;
      }

      const fallbackResult = await this.showOfflineInterstitialFallback(
        trigger,
        cooldownMs,
      );

      if (fallbackResult === "ad_shown") {
        return true;
      }

      if (fallbackResult === "fallback_completed") {
        this.markPendingOnlineAdRetry();
        return true;
      }

      return false;
    }
  }

  /**
   * 매칭되는 정책 찾기
   */
  private async findMatchingPolicy(
    context: AdContext,
  ): Promise<AdDisplayPolicy | null> {
    for (const policy of this.policies) {
      try {
        const shouldShow = await policy.shouldShow(context);
        if (shouldShow) {
          return policy;
        }
      } catch (error) {
        console.error(`[AdManager] Error in policy ${policy.name}:`, error);
      }
    }
    return null;
  }

  /**
   * 등록된 정책 목록
   */
  getPolicies(): AdDisplayPolicy[] {
    return [...this.policies];
  }

  /**
   * 쿨다운 리셋 (디버그용)
   */
  resetCooldown(): void {
    CooldownCondition.resetCooldown();
    this.clearPendingOnlineAdRetry();
  }

  /**
   * 강제로 광고 표시 (디버그용)
   */
  async forceShowAd(): Promise<boolean> {
    if (!window.adController) {
      console.warn("[AdManager] window.adController not available");
      return false;
    }

    try {
      await window.adController.showInterstitial({
        cooldownMs: DEFAULT_NATIVE_AD_COOLDOWN_MS,
      });
      CooldownCondition.updateCooldown();
      this.clearPendingOnlineAdRetry();
      return true;
    } catch (error) {
      console.error("[AdManager] Error forcing ad:", error);
      return false;
    }
  }

  hasPendingOnlineAdRetry(): boolean {
    if (typeof window === "undefined") {
      return false;
    }

    try {
      return localStorage.getItem(ONLINE_AD_RETRY_STORAGE_KEY) === "true";
    } catch {
      return false;
    }
  }

  private markPendingOnlineAdRetry(): void {
    if (typeof window === "undefined") {
      return;
    }

    try {
      localStorage.setItem(ONLINE_AD_RETRY_STORAGE_KEY, "true");
      console.log("[AdManager] Pending online ad retry marked");
    } catch (error) {
      console.warn("[AdManager] Failed to mark pending online ad retry", error);
    }
  }

  private clearPendingOnlineAdRetry(): void {
    if (typeof window === "undefined") {
      return;
    }

    try {
      localStorage.removeItem(ONLINE_AD_RETRY_STORAGE_KEY);
      console.log("[AdManager] Pending online ad retry cleared");
    } catch (error) {
      console.warn("[AdManager] Failed to clear pending online ad retry", error);
    }
  }

  private async showOfflineInterstitialFallback(
    trigger: string,
    cooldownMs: number,
  ): Promise<OfflineInterstitialFallbackResult> {
    const fallbackBridge =
      typeof window !== "undefined"
        ? window.digiviceAdFallbackBridge
        : undefined;

    if (!fallbackBridge?.showOfflineInterstitialFallback) {
      console.warn("[AdManager] Offline interstitial fallback unavailable");
      return false;
    }

    return new Promise<OfflineInterstitialFallbackResult>((resolve) => {
      let settled = false;
      let retryTimerId: number | null = null;

      const finish = (result: OfflineInterstitialFallbackResult) => {
        if (settled) {
          return;
        }

        settled = true;
        if (retryTimerId !== null) {
          window.clearTimeout(retryTimerId);
          retryTimerId = null;
        }

        resolve(result);
      };

      const scheduleRetry = () => {
        if (settled) {
          return;
        }

        retryTimerId = window.setTimeout(() => {
          retryTimerId = null;
          void retryAdConnection();
        }, OFFLINE_FALLBACK_AD_RETRY_INTERVAL_MS);
      };

      const retryAdConnection = async () => {
        if (settled) {
          return;
        }

        const didShow = await this.tryShowRecoveredInterstitial(cooldownMs);

        if (settled) {
          return;
        }

        if (didShow) {
          try {
            fallbackBridge.completeOfflineInterstitialFallback?.(true);
          } finally {
            finish("ad_shown");
          }
          return;
        }

        scheduleRetry();
      };

      fallbackBridge
        .showOfflineInterstitialFallback({
          trigger,
          cooldownMs,
          timestamp: Date.now(),
        })
        .then((completed) => {
          finish(completed === true ? "fallback_completed" : false);
        })
        .catch((fallbackError) => {
          console.error(
            "[AdManager] Error showing offline interstitial fallback:",
            fallbackError,
          );
          finish(false);
        });

      scheduleRetry();
    });
  }

  private async tryShowRecoveredInterstitial(cooldownMs: number): Promise<boolean> {
    if (!window.adController) {
      return false;
    }

    try {
      const canShowStr = await window.adController.canShowAd({ cooldownMs });
      if (canShowStr !== "true") {
        return false;
      }

      await window.adController.showInterstitial({ cooldownMs });
      console.log("[AdManager] Recovered ad shown during offline fallback");
      CooldownCondition.updateCooldown();
      this.clearPendingOnlineAdRetry();
      return true;
    } catch (error) {
      console.warn(
        "[AdManager] Recovered ad attempt failed during offline fallback",
        error,
      );
      return false;
    }
  }
}
